from scipy.linalg import eig
from scipy.linalg.lapack import dgeev

for n in range(2,11,2):
    As=[np.random.normal(size=(n,n)).astype(np.float64) for _ in range(1000)]
    def ref(A):
        w,v=np.linalg.eig(A); i=np.argmax(np.abs(w)); return w[i],v[:,i]
    def sp(A):
        w,v=eig(A, left=False, right=True, check_finite=False, overwrite_a=False)
        i=np.argmax(np.abs(w)); return w[i],v[:,i]
    def lap(A):
        wr,wi,vl,vr,info=dgeev(A, compute_vl=0, compute_vr=1, overwrite_a=0)
        # select using abs^2
        mags=wr*wr+wi*wi
        i=int(np.argmax(mags))
        val=wr[i]+1j*wi[i]
        if wi[i] == 0.0:
            vec=vr[:,i].astype(np.complex128)
        elif wi[i] > 0.0:
            vec=vr[:,i] + 1j*vr[:,i+1]
        else:
            vec=vr[:,i-1] - 1j*vr[:,i]
        return val, vec
    for name,fn in [('ref',ref),('sp',sp),('lap',lap)]:
        ts=[]
        for A in As[:200]: fn(A)
        for A in As:
            t=time.perf_counter(); fn(A); ts.append(time.perf_counter()-t)
        print(n,name,np.median(ts)*1e6)
    print()
