import numpy as np, time, cmath

As=[np.random.normal(size=(2,2)).astype(np.float64) for _ in range(10000)]

def ref(A):
    w,v=np.linalg.eig(A); i=np.argmax(np.abs(w)); return w[i],v[:,i]

def old(A):
    a=A[0,0]; b=A[0,1]; c=A[1,0]; d=A[1,1]
    half_trace=0.5*(a+d); delta=np.sqrt((0.5*(a-d))**2+b*c+0j)
    eigenvalue=half_trace+delta; other=half_trace-delta
    if (other.real*other.real+other.imag*other.imag) > (eigenvalue.real*eigenvalue.real+eigenvalue.imag*eigenvalue.imag): eigenvalue=other
    v0=np.array([b+0j,eigenvalue-a], dtype=np.complex128)
    v1=np.array([eigenvalue-d,c+0j], dtype=np.complex128)
    eigenvector=v0 if np.vdot(v0,v0).real >= np.vdot(v1,v1).real else v1
    if np.allclose(eigenvector,0): eigenvector=np.array([1+0j,0j])
    return eigenvalue,eigenvector

def new(A):
    a=A[0,0]; b=A[0,1]; c=A[1,0]; d=A[1,1]
    h=0.5*(a+d)
    diff=0.5*(a-d)
    root=cmath.sqrt(diff*diff + b*c)
    ev=h+root
    other=h-root
    if (other.real*other.real+other.imag*other.imag) > (ev.real*ev.real+ev.imag*ev.imag):
        ev=other
    y=ev-a
    u=ev-d
    n0=b*b + y.real*y.real + y.imag*y.imag
    n1=u.real*u.real + u.imag*u.imag + c*c
    if n0 >= n1:
        if n0 == 0.0:
            vec=np.array([1.0+0j, 0j])
        else:
            vec=np.array([b+0j, y])
    else:
        vec=np.array([u, c+0j])
    return ev, vec

# validate
for A in As[:1000]:
    for fn in [new]:
      val,vec=fn(A)
      if not np.allclose(A@vec,val*vec): print('fail',A,val,vec,A@vec-val*vec); raise SystemExit
for name,fn in [('ref',ref),('old',old),('new',new)]:
    ts=[]
    for A in As[:1000]: fn(A)
    for A in As:
        t=time.perf_counter(); fn(A); ts.append(time.perf_counter()-t)
    print(name,np.median(ts)*1e6)
